function maxPoints(grid, queries) {
    const m = grid.length;
    const n = grid[0].length;
    const dx = [-1, 0, 1, 0];
    const dy = [0, 1, 0, -1];

    function dfs(x, y, q, visited) {
        if (0 <= x && x < m && 0 <= y && y < n && grid[x][y] < q && !visited.has(`${x},${y}`)) {
            visited.add(`${x},${y}`);
            let points = 1;
            for (let i = 0; i < 4; i++) {
                const nx = x + dx[i], ny = y + dy[i];
                points += dfs(nx, ny, q, visited);
            }
            return points;
        }
        return 0;
    }

    return queries.map(query => dfs(0, 0, query, new Set()));
}
```


    The algorithm for this problem is essentially a depth-first search on the grid. For each query, start at the top left of the grid and perform a DFS. 

1. If the cell has not been visited and the value of the cell is strictly lower than the query value, add the cell to the visited set, increment the points, and continue the DFS for all 4 adjacent cells.
2. If the cell is visited or the value is not lower than the query, the DFS terminates for that path.

This process is repeated for all queries, and the answer array is returned with the maximum points for each query.

