import java.util.*;

public List<Integer> maxPoints(int[][] grid, int[] queries) {
    int m = grid.length;
    int n = grid[0].length;
    int[] dx = {-1, 0, 1, 0};
    int[] dy = {0, 1, 0, -1};
    List<Integer> result = new ArrayList<>();

    for (int query : queries) {
        int points = 0;
        Set<String> visited = new HashSet<>();
        Stack<int[]> stack = new Stack<>();
        stack.push(new int[]{0, 0});

        while (!stack.isEmpty()) {
            int[] cur = stack.pop();
            int x = cur[0], y = cur[1];
            String coordStr = x + "," + y;

            if (!visited.contains(coordStr) && grid[x][y] < query) {
                visited.add(coordStr);
                points++;
                for (int i = 0; i < 4; i++) {
                    int nx = x + dx[i], ny = y + dy[i];
                    if (nx >= 0 && nx < m && ny >= 0 && ny < n) {
                        stack.push(new int[]{nx, ny});
                    }
                }
            }
        }
        result.add(points);
    }
    return result;
}
```


